#include "main.h"
#include "FreeRTOS.h"
#include "queue.h"
#include "task.h"
#include "mppt_internal.h"
#include "mppt.h"
#include "hrtim.h"

extern QueueHandle_t adc_queue;
static float now_current_A = 0.0f, now_voltage_mV = 0.0f;

#define RC_ALPHA_DENO_1        0.85f
#define RC_ALPHA_DENO_2        0.10f
#define RC_ALPHA_DENO_3        0.05f

#define MPPT_DUTY_MIN          500U
#define MPPT_DUTY_MAX          54000U
#define MPPT_DUTY_INIT         0U
#define MPPT_DUTY_STEP         80U
#define MPPT_POWER_EPS_W       0.03f
#define MPPT_CTRL_UPDATE_DIV   8U
#define MPPT_TASK_STACK_WORDS  256U
#define MPPT_TASK_PRIORITY     9U

void pwm_set_duty(uint32_t pwm_duty) //占空比0-54400
{
    __HAL_HRTIM_SETCOMPARE(&hhrtim1, HRTIM_TIMERINDEX_TIMER_E, HRTIM_COMPAREUNIT_3, (pwm_duty >> 1) + 1);
    hhrtim1.Instance->sTimerxRegs[TIMER_E].CMP1CxR = pwm_duty;
}

float get_voltage_value(uint8_t index)
{
    if(index == 0)
        return now_voltage_mV;
    if(index == 1)
        return now_current_A;

    return 0.0f;
}

static float last_last_voltage_mV = 0.0f;

static inline __attribute__((always_inline)) void adc_data_process(uint32_t *data_buf)
{
    float origin_voltage_sum = 0.0f, origin_current_sum = 0.0f;
    for(uint8_t i = 0; i < ADC_BUFFER_LENGTH / 2; i++)
    {
        origin_voltage_sum += data_buf[i] & 0x0FFF;
        origin_current_sum += data_buf[i] >> 16;
    }
    // origin_voltage_sum / 4095 * 3300 / 20(样本量) = adc引脚上的电压
    // * 20 = 运放输入电压(运放20分压)
    // * 1.0079(adc误差修正)
    float temp_voltage_mV = origin_voltage_sum * 3300.0f / 4095.0f / (float)(ADC_BUFFER_LENGTH / 2) * 20.0f *
                            1.0079f;

    now_current_A = origin_current_sum * 3300.0f / 4095.0f / (ADC_BUFFER_LENGTH / 2) * 2.0f / 1000.0f; //单位A

    //对均值进行二阶rc滤波
    temp_voltage_mV = RC_ALPHA_DENO_1 * temp_voltage_mV + RC_ALPHA_DENO_2 * now_voltage_mV +
                      RC_ALPHA_DENO_3 * last_last_voltage_mV;

    last_last_voltage_mV = now_voltage_mV;
    now_voltage_mV = temp_voltage_mV;
}

static inline uint32_t clamp_duty(int32_t duty)
{
    if(duty < (int32_t)MPPT_DUTY_MIN)
        return MPPT_DUTY_MIN;
    if(duty > (int32_t)MPPT_DUTY_MAX)
        return MPPT_DUTY_MAX;
    return (uint32_t)duty;
}

void mppt_routine(void *args)
{
    static uint32_t *buf_ptr;
    uint32_t duty = MPPT_DUTY_INIT;
    int8_t direction = 1;
    uint8_t update_div_cnt = 0;

    float prev_power_w = 0.0f;
    uint8_t initialized = 0;

    pwm_set_duty(duty);

    (void)args;
    while(1)
    {
        //1. 等待ADC数据
        if(xQueueReceive(adc_queue, &buf_ptr, portMAX_DELAY) == pdTRUE)
        {
            adc_data_process(buf_ptr);

            if(++update_div_cnt < MPPT_CTRL_UPDATE_DIV)
                continue;
            update_div_cnt = 0;

            // V(mV) * I(A) => mW
            float now_power_w = (now_voltage_mV * now_current_A) / 1000.0f;

            if(!initialized)
            {
                prev_power_w = now_power_w;
                initialized = 1;
                continue;
            }

            float d_power = now_power_w - prev_power_w;

            if(d_power < -MPPT_POWER_EPS_W)
                direction = -direction;

            duty = clamp_duty((int32_t)duty + direction * (int32_t)MPPT_DUTY_STEP);

            if((duty == MPPT_DUTY_MIN && direction < 0) || (duty == MPPT_DUTY_MAX && direction > 0))
                direction = -direction;

            pwm_set_duty(duty);
            prev_power_w = now_power_w;
        }
    }
}

void MPPT_init(void)
{
    xTaskCreate(mppt_routine, "MPPT", MPPT_TASK_STACK_WORDS, NULL, MPPT_TASK_PRIORITY, NULL);
}

#include "main.h"
#include "FreeRTOS.h"
#include "queue.h"
#include "task.h"
#include "mppt_internal.h"
#include "mppt.h"
#include "hrtim.h"

extern QueueHandle_t adc_queue;
static float now_current_A = 0.0f, now_voltage_mV = 0.0f;

#define RC_ALPHA_DENO_1        0.85f
#define RC_ALPHA_DENO_2        0.10f
#define RC_ALPHA_DENO_3        0.05f

#define MPPT_DUTY_MIN          500U
#define MPPT_DUTY_MAX          54000U
#define MPPT_DUTY_INIT         0U
#define MPPT_DUTY_STEP_MIN     20U
#define MPPT_DUTY_STEP_MID     80U
#define MPPT_DUTY_STEP_MAX     200U
/*
 * MPPT_POWER_EPS_W: 功率变化死区阈值(单位W)。
 * |dP| 小于该值时认为变化主要来自采样噪声，不触发方向反转。
 */
#define MPPT_POWER_EPS_W       0.03f
#define MPPT_DP_SMALL_W        0.10f
#define MPPT_DP_LARGE_W        0.50f
#define MPPT_CTRL_UPDATE_DIV   8U
#define MPPT_TASK_STACK_WORDS  256U
#define MPPT_TASK_PRIORITY     9U

void pwm_set_duty(uint32_t pwm_duty) //占空比0-54400
{
    __HAL_HRTIM_SETCOMPARE(&hhrtim1, HRTIM_TIMERINDEX_TIMER_E, HRTIM_COMPAREUNIT_3, (pwm_duty >> 1) + 1);
    hhrtim1.Instance->sTimerxRegs[TIMER_E].CMP1CxR = pwm_duty;
}

float get_voltage_value(uint8_t index)
{
    if(index == 0)
        return now_voltage_mV;
    if(index == 1)
        return now_current_A;

    return 0.0f;
}

static float last_last_voltage_mV = 0.0f;

static inline __attribute__((always_inline)) void adc_data_process(uint32_t *data_buf)
{
    float origin_voltage_sum = 0.0f, origin_current_sum = 0.0f;
    for(uint8_t i = 0; i < ADC_BUFFER_LENGTH / 2; i++)
    {
        origin_voltage_sum += data_buf[i] & 0x0FFF;
        origin_current_sum += data_buf[i] >> 16;
    }
    // origin_voltage_sum / 4095 * 3300 / 20(样本量) = adc引脚上的电压
    // * 20 = 运放输入电压(运放20分压)
    // * 1.0079(adc误差修正)
    float temp_voltage_mV = origin_voltage_sum * 3300.0f / 4095.0f / (float)(ADC_BUFFER_LENGTH / 2) * 20.0f *
                            1.0079f;

    now_current_A = origin_current_sum * 3300.0f / 4095.0f / (ADC_BUFFER_LENGTH / 2) * 2.0f / 1000.0f; //单位A

    //对均值进行二阶rc滤波
    temp_voltage_mV = RC_ALPHA_DENO_1 * temp_voltage_mV + RC_ALPHA_DENO_2 * now_voltage_mV +
                      RC_ALPHA_DENO_3 * last_last_voltage_mV;

    last_last_voltage_mV = now_voltage_mV;
    now_voltage_mV = temp_voltage_mV;
}

static inline uint32_t clamp_duty(int32_t duty)
{
    if(duty < (int32_t)MPPT_DUTY_MIN)
        return MPPT_DUTY_MIN;
    if(duty > (int32_t)MPPT_DUTY_MAX)
        return MPPT_DUTY_MAX;
    return (uint32_t)duty;
}

static inline uint32_t mppt_step_by_dp(float abs_dp)
{
    if(abs_dp >= MPPT_DP_LARGE_W)
        return MPPT_DUTY_STEP_MAX;
    if(abs_dp >= MPPT_DP_SMALL_W)
        return MPPT_DUTY_STEP_MID;
    return MPPT_DUTY_STEP_MIN;
}

void mppt_routine(void *args)
{
    static uint32_t *buf_ptr;
    uint32_t duty = MPPT_DUTY_INIT;
    int8_t direction = 1;
    uint8_t update_div_cnt = 0;

    float prev_power_w = 0.0f;
    uint8_t initialized = 0;

    pwm_set_duty(duty);

    (void)args;
    while(1)
    {
        //1. 等待ADC数据
        if(xQueueReceive(adc_queue, &buf_ptr, portMAX_DELAY) == pdTRUE)
        {
            adc_data_process(buf_ptr);

            if(++update_div_cnt < MPPT_CTRL_UPDATE_DIV)
                continue;
            update_div_cnt = 0;

            // V(mV) * I(A) => mW
            float now_power_w = (now_voltage_mV * now_current_A) / 1000.0f;

            if(!initialized)
            {
                prev_power_w = now_power_w;
                initialized = 1;
                continue;
            }

            float d_power = now_power_w - prev_power_w;
            float abs_d_power = (d_power >= 0.0f) ? d_power : -d_power;
            uint32_t duty_step = mppt_step_by_dp(abs_d_power);

            if(d_power < -MPPT_POWER_EPS_W)
                direction = -direction;

            duty = clamp_duty((int32_t)duty + direction * (int32_t)duty_step);

            if((duty == MPPT_DUTY_MIN && direction < 0) || (duty == MPPT_DUTY_MAX && direction > 0))
                direction = -direction;

            pwm_set_duty(duty);
            prev_power_w = now_power_w;
        }
    }
}

void MPPT_init(void)
{
    xTaskCreate(mppt_routine, "MPPT", MPPT_TASK_STACK_WORDS, NULL, MPPT_TASK_PRIORITY, NULL);
}
